// Enhanced validation with rate limiting and sanitization
const message = $input.item.json.message;

// Basic message validation
if (!message || !message.text || !message.chat || !message.chat.id) {
	throw new Error('Invalid message format received');
}

// Sanitize user input
function sanitizeText(text) {
	return text
		.trim()
		.replace(/[\x00-\x1F\x7F]/g, '')
		.replace(/<script[^>]*>.*?<\/script>/gi, '')
		.replace(/<[^>]+>/g, '')
		.replace(/javascript:/gi, '')
		.substring(0, 1000);
}

const sanitizedText = sanitizeText(message.text);

// Validar caracteres permitidos
const allowedPattern = /^[a-zA-ZÀ-ÿ0-9\s.,!?;:()\-"'áéíóúãõâêôàèìòùçñü/]+$/;
if (!allowedPattern.test(sanitizedText)) {
	throw new Error('❌ Texto contém caracteres inválidos. Use apenas letras, números e pontuação básica.');
}

// Enhanced logging
const logEntry = {
	timestamp: new Date().toISOString(),
	event: 'telegram_message_received',
	chatId: message.chat.id,
	username: message.from?.username || 'unknown',
	firstName: message.from?.first_name || '',
	messageText: sanitizedText,
	originalLength: message.text.length,
	sanitizedLength: sanitizedText.length,
	messageId: message.message_id,
	workflowExecutionId: $execution.id
};

console.log('Incoming message:', JSON.stringify(logEntry));

// Enhanced content validation
if (sanitizedText.length > 1000) {
	throw new Error('❌ Mensagem muito longa. Mantenha abaixo de 1000 caracteres.');
}

if (sanitizedText.length < 1) {
	throw new Error('❌ Mensagem muito curta. Forneça mais detalhes.');
}

return {
	...message,
	text: sanitizedText,
	originalText: message.text,
	validatedAt: new Date().toISOString(),
	textLength: sanitizedText.length,
	contentValidated: true,
	sanitized: true
};

// Enhanced user state processing with cleanup logic
const dbResult = $input.item.json;
const message = $('Telegram Trigger1').item.json.message;

let userState = {
	hasActiveSession: false,
	lastRecord: null,
	nextAction: 'create_new',
	chatId: message.chat.id,
	messageText: message.text,
	originalTheme: message.text, // Store original theme before processing
	outputIndex: 0,
	error: null,
	userInfo: {
		username: message.from?.username || 'unknown',
		firstName: message.from?.first_name || '',
		languageCode: message.from?.language_code || 'pt'
	}
};

try {
	let record = null;

	if (Array.isArray(dbResult) && dbResult.length > 0) {
		record = dbResult[0];
	} else if (dbResult && typeof dbResult === 'object' && dbResult.id) {
		record = dbResult;
	}

	if (record && record.id) {
		userState.hasActiveSession = true;
		userState.lastRecord = record;

		// Check for cleanup confirmation state FIRST
		if (record.status === 'awaiting_cleanup') {
			const msgLower = message.text.toLowerCase().trim();
			// Preserve original theme from the record that triggered cleanup
			userState.originalTheme = record.original_theme || record.theme || message.text;

			if (msgLower === 'confirmar' || msgLower.includes('confirmar')) {
				userState.nextAction = 'confirm_cleanup';
				userState.outputIndex = 5;
			} else if (msgLower === 'cancelar' || msgLower.includes('cancelar')) {
				userState.nextAction = 'cancel_cleanup';
				userState.outputIndex = 6;
			} else {
				userState.nextAction = 'request_cleanup_confirmation';
				userState.outputIndex = 7;
			}
			return userState;
		}

		// Check for command words BEFORE processing normal status
		const msgLower = message.text.toLowerCase().trim();
		if (msgLower === 'confirmar' || msgLower === 'cancelar') {
			// If we have a record but it's not in awaiting_cleanup state,
			// and user sends confirmar/cancelar, treat as new theme
			userState.nextAction = 'check_for_drafts';
			userState.outputIndex = 8;
			return userState;
		}

		// Normal status logic
		switch(record.status) {
			case 'pending_feedback':
				userState.nextAction = 'process_feedback';
				userState.outputIndex = 1;
				break;

			case 'draft':
				const msgLower = message.text.toLowerCase().trim();
				if (msgLower.includes('aprovar') || msgLower === 'aprovar') {
					userState.nextAction = 'approve_draft';
					userState.outputIndex = 2;
				} else if (msgLower.includes('refazer') || msgLower === 'refazer') {
					userState.nextAction = 'request_changes';
					userState.outputIndex = 3;
				} else {
					userState.nextAction = 'check_for_drafts';
					userState.outputIndex = 8;
				}
				break;

			case 'approved':
			case 'generating':
			case 'uploading':
				userState.nextAction = 'show_status';
				userState.outputIndex = 4;
				break;

			default:
				userState.nextAction = 'check_for_drafts';
				userState.outputIndex = 8;
		}
	} else {
		userState.nextAction = 'check_for_drafts';
		userState.outputIndex = 8;
	}
} catch (error) {
	console.error('Error processing user state:', error);
	userState.error = error.message;
	userState.nextAction = 'create_new';
	userState.outputIndex = 0;
}

console.log('User state determined:', {
	hasActiveSession: userState.hasActiveSession,
	action: userState.nextAction,
	outputIndex: userState.outputIndex,
	currentTheme: userState.messageText,
	previousTheme: userState.lastRecord?.theme || 'none'
});

return userState;

// Enhanced script validation and data preparation
const script = $input.item.json.text || $input.item.json.content;
const message = $('Process User State').item.json.messageText;
const chatId = $('Process User State').item.json.chatId;
const userInfo = $('Process User State').item.json.userInfo;

// Enhanced script validation
if (!script || typeof script !== 'string') {
	throw new Error('Invalid script format received from AI.');
}

const cleanScript = script.trim();
if (cleanScript.length < 50) {
	throw new Error('Script too short. Please try a more detailed theme.');
}

if (cleanScript.length > 1500) {
	throw new Error('Script too long. Please try a more focused theme.');
}

// Enhanced inappropriate content detection
const inappropriateWords = [
	'violência', 'drogas', 'sexo', 'ódio', 'discriminação',
	'suicídio', 'automutilação', 'bullying', 'assédio',
	'terrorismo', 'armas', 'explosivos', 'pornografia',
	'racismo', 'homofobia', 'xenofobia', 'preconceito'
];

const scriptLower = cleanScript.toLowerCase();
for (const word of inappropriateWords) {
	if (scriptLower.includes(word)) {
		throw new Error('Generated script contains inappropriate content. Please try a different theme.');
	}
}

// Quality checks
const wordCount = cleanScript.split(/\s+/).length;
if (wordCount > 250) {
	console.warn('Script may be too long for 60 seconds:', wordCount, 'words');
}

// Enhanced data preparation
const now = new Date().toISOString();
const recordId = 'yt_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);

// Estimate reading time (average 150 words per minute)
const estimatedDuration = Math.round((wordCount / 150) * 60);

const result = {
	id: recordId,
	chat_id: chatId,
	username: userInfo.username || 'user',
	theme: message,
	script: cleanScript,
	status: 'draft',
	feedback_count: 0,
	created_at: now,
	updated_at: now,
	word_count: wordCount,
	estimated_duration: estimatedDuration,
	language_code: userInfo.languageCode || 'pt'
};

console.log('Script prepared:', {
	id: recordId,
	wordCount: wordCount,
	estimatedDuration: estimatedDuration,
	theme: message
});

return result;

