// Enhanced dynamic video generation based on theme
const theme = $('Process User State').item.json.lastRecord.theme;
const script = $('Process User State').item.json.lastRecord.script;

// Advanced video template selection
const videoTemplates = {
	'café': 'https://sample-videos.com/video321/mp4/720/coffee_template.mp4',
	'culinária': 'https://sample-videos.com/video321/mp4/720/cooking_template.mp4',
	'tecnologia': 'https://sample-videos.com/video321/mp4/720/tech_template.mp4',
	'saúde': 'https://sample-videos.com/video321/mp4/720/health_template.mp4',
	'educação': 'https://sample-videos.com/video321/mp4/720/education_template.mp4',
	'dicas': 'https://sample-videos.com/video321/mp4/720/tips_template.mp4',
	'negócios': 'https://sample-videos.com/video321/mp4/720/business_template.mp4',
	'fitness': 'https://sample-videos.com/video321/mp4/720/fitness_template.mp4',
	'viagem': 'https://sample-videos.com/video321/mp4/720/travel_template.mp4',
	'default': 'https://sample-videos.com/video321/mp4/720/big_buck_bunny_720p_1mb.mp4'
};

// Smart theme detection
let selectedTemplate = videoTemplates.default;
let matchedKeyword = 'default';
const themeLower = theme.toLowerCase();

// Find best matching template
for (const [keyword, template] of Object.entries(videoTemplates)) {
	if (keyword !== 'default' && themeLower.includes(keyword)) {
		selectedTemplate = template;
		matchedKeyword = keyword;
		break;
	}
}

// Generate unique video ID for tracking
const videoId = 'vid_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);

const videoUrl = selectedTemplate;

console.log('Video generation:', {
	theme: theme,
	matchedKeyword: matchedKeyword,
	selectedTemplate: selectedTemplate,
	videoId: videoId
});

return {
	videoUrl: videoUrl,
	templateUsed: matchedKeyword,
	videoId: videoId,
	theme: theme,
	script: script,
	generatedAt: new Date().toISOString()
};

