// Preparar lista detalhada de rascunhos com contador e validação
const inputData = $input.all();
const message = $('Telegram Trigger1').item.json.message;

let drafts = [];
if (Array.isArray(inputData)) {
	drafts = inputData.map(item => item.json);
} else if (inputData && inputData.json) {
	drafts = [inputData.json];
}

// Filtrar registros válidos e limpar dados corrompidos
drafts = drafts.filter(draft => {
	return draft && (draft.id || draft.chat_id); // Pelo menos ID ou chat_id deve existir
}).map(draft => {
	// Limpar e validar campos
	return {
		id: draft.id || 'ID não disponível',
		chat_id: draft.chat_id || 'N/A',
		username: draft.username || 'unknown',
		theme: draft.theme || 'Sem tema',
		script: draft.script || 'Script não disponível',
		status: draft.status || 'unknown',
		created_at: draft.created_at || null,
		updated_at: draft.updated_at || null
	};
});

if (drafts.length === 0) {
	// Não retornar dados para permitir que Has Drafts? funcione corretamente
	return [];
}

// Contar por status
const statusCount = {};
drafts.forEach(draft => {
	statusCount[draft.status] = (statusCount[draft.status] || 0) + 1;
});

// Criar lista formatada com contador
let draftList = `📋 *${drafts.length} Temas não finalizados encontrados:*\n\n`;

// Agrupar por tema para evitar repetição
const themeGroups = {};
drafts.forEach(draft => {
	const theme = draft.theme || 'Sem tema';
	if (!themeGroups[theme]) {
		themeGroups[theme] = [];
	}
	themeGroups[theme].push(draft);
});

// Listar temas agrupados
let itemIndex = 1;
Object.keys(themeGroups).forEach(theme => {
	const group = themeGroups[theme];
	const firstDraft = group[0];

	// Determinar emoji baseado no status
	const statusEmoji = {
		'draft': '📝',
		'pending_feedback': '⏳',
		'approved': '✅',
		'generating': '🎬',
		'uploading': '📤',
		'awaiting_cleanup': '🗑️'
	}[firstDraft.status] || '❓';

	const date = firstDraft.created_at ? 
		new Date(firstDraft.created_at).toLocaleDateString('pt-BR') : 
		'Data não disponível';

	if (group.length === 1) {
		draftList += `${itemIndex}. ${statusEmoji} *${theme}*\n`;
		draftList += `		📅 Criado em: ${date}\n`;
		draftList += `		🆔 ID: ${firstDraft.id}\n\n`;
	} else {
		draftList += `${itemIndex}. ${statusEmoji} *${theme}*\n`;
		draftList += `		📊 **${group.length} registros duplicados**\n`;
		draftList += `		📅 Criado em: ${date}\n`;
		draftList += `		🆔 IDs: ${group.map(d => d.id).join(', ')}\n\n`;
	}
	itemIndex++;
});

// Estatísticas
draftList += `📊 **Resumo:**\n`;
draftList += `• Total de registros: ${drafts.length}\n`;
draftList += `• Temas únicos: ${Object.keys(themeGroups).length}\n`;
Object.keys(statusCount).forEach(status => {
	const emoji = status === 'draft' ? '📝' : '❓';
	draftList += `• ${emoji} ${status}: ${statusCount[status]}\n`;
});

// Get original theme from user state (passed through the flow)
const originalTheme = $('Process User State').item.json.originalTheme || message.text;
draftList += `\n⚠️ *Para criar o novo tema '${originalTheme}', preciso limpar TODOS estes ${drafts.length} rascunhos.*\n\n`;
draftList += "✅ Digite `confirmar` para deletar **TODOS** e continuar\n";
draftList += "❌ Digite `cancelar` para manter os rascunhos\n\n";
draftList += `💡 *Atenção: Serão deletados todos os ${drafts.length} registros listados acima!*`;

return {
	chatId: message.chat.id,
	hasDrafts: true,
	draftCount: drafts.length,
	uniqueThemes: Object.keys(themeGroups).length,
	message: draftList,
	currentTheme: originalTheme,
	draftsToDelete: drafts.map(d => d.id),
	statusBreakdown: statusCount
};
